import Store from "../store/index";
// 搜索方法
// dL为dataList,hT 选出行所用的列header，hT所对应的值，vT筛选一行中所需的数据，多个则用数组表示
// 结果用数组表示，包含每组数据所应存放的地点和值，
// pos确定位置是依赖于行标题去找还是列标题去找，h为行，v为列
// ifV是确定值所依据的项，ifV == undefine，存放的是值，typeOf ifV == object,存放的是标题，  typeOf ifV == 'string' 存放的是该字符串所代表的值
// addToBasis为要添加到basis的过程数据,是 一个数组，addToBasis[0]对象的属性名，addToBasis[1]为对应的列属性值；
export function search(dL, hT, hP, vT, pos, corner, ifV, addToBasis) {
  console.log("in handler");
  let rows;
  if (typeof hT == "string") {
    rows = dL.filter((v) => {
      return hP.includes(v[hT]) || v[hT].includes(hP);
    }); // 可能有多行
  } else {
    console.log("多个ht");
    hT.forEach((key, i) => {
      rows = (
        rows ||
        dL.filter((v) => {
          return hP[i].includes(v[key]) || v[key].includes(hP[i]); // hp包含hT
        })
      ).filter((k) => k[key].includes(hP[i]) || hP[i].includes(k[key])); // hT包含hP,这里特殊处理，有需要再做其他处理
    });
  }

  let res = [];
  if (!(rows instanceof Array)) {
    rows = [rows];
  }
  console.log("rowrowrow");
  rows.forEach((item) => {
    // 每行可能有多个，取决于vT的个数
    if (typeof vT == "string") {
      let obj = {};
      // 判断位置是根据行标题来找还是列标题
      if (pos == "v") {
        obj.pos = item[vT];
      } else {
        obj.pos = item[hT];
      }
      obj.corner = corner;
      if (typeof ifV == "undefined") {
        obj[vT] = item[vT];
      } else if (typeof ifV === "object") {
        obj[vT] = ifV[vT];
      } else if (typeof ifV == "string") {
        obj[vT] = item[ifV];
      }
      res.push(obj);
    } else {
      // 取列值
      console.log("3 for each");
      if (typeof ifV == "undefined") {
        console.log("ifV is Undefined");
        vT.forEach((v) => {
          let obj = {};
          obj.pos = item[v];
          obj.corner = corner;
          obj[v] = item[v];
          res.push(obj);
        });
      } else if (typeof ifV === "object") {
        // 取列标题
        vT.forEach((v) => {
          let obj = {};
          obj.pos = item[v];
          obj.corner = corner;
          obj[v] = ifV[v];
          res.push(obj);
        });
      } else if (typeof ifV == "string") {
        // 取另一个属性的值
        vT.forEach((v) => {
          let obj = {};
          obj.pos = item[v];
          obj.corner = corner;
          obj[v] == item[ifV];
          res.push(obj);
        });
      }
    }
    // 如果有要添加到basis的过程数据，则进行添加
    if (addToBasis) {
      let obj = {};
      for (let i = 0; i < addToBasis[0].length; i++) {
        obj[addToBasis[0][i]] = item[addToBasis[1][i]];
        console.log("item :>> ", item);
      }
      console.log("after item");
      Store.commit("ADD_TO_BASIS", obj);
    }
  });
  return res;
}
