import Vue from "vue";
import Vuex from "vuex";
import { source, tableData as TD } from "../utils/dataBuild.js";

Vue.use(Vuex);

export default new Vuex.Store({
  state: {
    basis: {},
    basisShow: {
      nianzhi: "年支",
      niangan: "年干",
      date: "出生日期",
      hour: "时辰",
      sex: "性别",
      wuxing: "五行",
      yinyang: "阴阳",
      hualu: "化禄",
      huake: "化科",
      huaquan: "化权",
      huaji: "化忌",
      mingzhu: "命主",
      mingshen: "命身",
    },
  },
  getters: {
    shiGanSuoShu: (state) => [
      TD.shiGanSuoShu,
      "niangan",
      source.tiangan10o[state.basis.niangan],
      "yinyang",
      "v",
      6,
      source.shigansuoshu,
      [["yinyang"], ["yinyang"]],
    ],
    anMingGongJiShenGong: (state) => [
      TD.anMingGongJiShenGong,
      "bornTime",
      state.basis.hour,
      Object.keys(source.month12)[state.basis.month - 1],
      "v",
      4,
      "mingshen",
      [["minggong"], [Object.keys(source.month12)[state.basis.month - 1]]],
    ],
    dingShiErGong: (state) => [
      TD.dingShiErGong,
      "minggong",
      state.basis.minggong,
      Object.keys(source.around),
      "v",
      4,
      source.around,
      [Object.keys(source.around), Object.keys(source.around)],
    ],
    dingShiErGongTianGan: (state) => {
      let hPList = Object.keys(source.around).map((n) => {
        return state.basis[n];
      });
      hPList.push(state.basis.minggong);
      console.log(
        "state.basic.mingshennnnnnnnnnnnn :>> ",
        state.basis.minggong
      );
      // hPList.push(state.basis.minggong);
      let hTitle = ["wukui", "dingren", "bingxin", "yigeng", "jiasi"];
      return [
        TD.dingShiErGongTianGan,
        "shiergong",
        hPList,
        hTitle.find((ht) => ht.includes(state.basis.niangan)),
        "h",
        5,
      ];
    },
    dingWuXingJu: (state) => {
      let hTitle = ["wukui", "dingren", "bingxin", "yigeng", "jiasi"];
      let vT = hTitle.find((ht) => ht.includes(state.basis.niangan));
      return [
        TD.dingWuXingJu,
        "minggong",
        state.basis.minggong,
        vT,
        "h",
        6,
        undefined,
        [["wuxing"], [vT]],
      ];
    },
    qiZiWei: (state) => [
      TD.qiZiWei,
      "bornday",
      source.bornday[Object.keys(source.bornday)[state.basis.day - 1]],
      Object.keys(source.xing5).find(
        (x) => source.xing5[x] == state.basis.wuxing
      ),
      "v",
      6,
      undefined,
      [
        ["ziwei"],
        [
          Object.keys(source.xing5).find(
            (x) => source.xing5[x] == state.basis.wuxing
          ),
        ],
      ],
    ],
    anZiWeiZhuXingChen: (state) => [
      TD.anZiWeiZhuXingChen,
      "ziwei",
      state.basis.ziwei,
      Object.keys(source.zhuxing),
      "v",
      1,
      source.zhuxing,
      // [Object.keys(source.around), Object.keys(source.around)],
    ],
    dingTianFu: (state) => [
      TD.dingTianFu,
      "ziwei",
      state.basis.ziwei,
      "tianfu",
      "v",
      6,
      undefined,
      [["tianfu"], ["tianfu"]],
    ],
    anTianFuZhuXingChen: (state) => [
      TD.anTianFuZhuXingChen,
      "tianfu",
      state.basis.tianfu,
      Object.keys(source.tianfuxingchen),
      "v",
      1,
      source.tianfuxingchen,
    ],
    anShiXiZhuXingChen: (state) => {
      let timegroup = {
        xuwuyin: "戌午寅",
        chenzishen: "辰子申",
        chouyousi: "丑酉巳",
        weimaohai: "未卯亥",
      };
      let time;
      for (let n in timegroup) {
        if (timegroup[n].includes(state.basis.nianzhi)) {
          time = n;
        }
      }
      let vTList = [
        "wenchang",
        "wenqu",
        time + "huoxing",
        time + "lingxing",
        "dijie",
        "dikong",
        "taifu",
        "fenggao",
      ];
      return [
        TD.anShiXiZhuXingChen,
        "borntime",
        state.basis.hour,
        vTList,
        "v",
        1,
        source.anShiXiZhuXingChen,
      ];
    },
    anYueXiZhuXingChen: (state) => [
      TD.anYueXiZhuXingChen,
      "month",
      source.month12[Object.keys(source.month12)[state.basis.month - 1]],
      Object.keys(source.yuexixingchen),
      "v",
      1,
      source.yuexixingchen,
    ],
    anGanXiZhuXingChen: (state) => {
      return [
        TD.anGanXiZhuXingChen,
        "niangan",
        source.tiangan10o[state.basis.niangan],
        Object.keys(source.ganxixingchen),
        "v",
        1,
        source.ganxixingchen,
        [
          ["hualu", "huaquan", "huake", "huaji"],
          ["hualu", "huaquan", "huake", "huaji"],
        ],
      ];
    },
    anZhiXiZhuXingChen: (state) => [
      TD.anZhiXiZhuXingChen,
      "nianzhi",
      state.basis.nianzhi,
      Object.keys(source.zhixixingchen),
      "v",
      2,
      source.zhixixingchen,
      [["tiancai"], ["tiancai"]],
    ],
    anWuXingChangShengShiErXing: (state) => [
      TD.anWuXingChangShengShiErXing,
      ["wuxing", "shunni"],
      [state.basis.wuxing, state.basis.yinyang + state.basis.sex],
      Object.keys(source.wuxingchangsheng),
      "v",
      3,
      source.wuxingchangsheng,
      [["shunni"], ["shunni"]],
    ],
    anJieLuKongWang: (state) => [
      TD.anJieLuKongWang,
      "niangan",
      source.tiangan10o[state.basis.niangan],
      ["xingming"],
      "v",
      3,
      { xingming: "空亡" },
      [["xunkong"], ["xingming"]],
    ],
    anXunZhongKongWang: (state) => {
      let key;
      for (let i in source.xunkong) {
        if (source.xunkong[i].includes(state.basis.xunkong)) key = i;
      }
      return [
        TD.anXunZhongKongWang,
        "niangan",
        source.tiangan10o[state.basis.niangan],
        [key],
        "v",
        3,
        {
          wuhai: "旬中",
          shenyou: "旬中",
          wuwei: "旬中",
          chensi: "旬中",
          yinmao: "旬中",
          zichou: "旬中",
        },
      ];
    },
    anMingZhu: (state) => [
      TD.anMingZhu,
      "minggong",
      state.basis.minggong,
      ["mingzhu"],
      "v",
      6,
      { mingzhu: "命主" },
      [["mingzhu"], ["mingzhu"]],
    ],
    anShenZhu: (state) => [
      TD.anShenZhu,
      "nianzhi",
      state.basis.nianzhi,
      ["shenzhu"],
      "v",
      6,
      { shenzhu: "身主" },
      [["shenzhu"], ["shenzhu"]],
    ],
    qiDaXian: (state) => [
      TD.qiDaXian,
      ["wuxing", "yinyang"],
      [state.basis.wuxing, state.basis.yinyang + state.basis.sex],
      Object.keys(source.daxiangong),
      "v",
      4,
      source.daxiangong,
    ],
  },
  mutations: {
    // 用户信息
    SET_BASIS(state, basis) {
      state.basis = basis;
    },
    ADD_TO_BASIS(state, obj) {
      state.basis = Object.assign(state.basis, obj);
    },
    // val => [{month:'亥'，mingshen: "ming"},{month:'巳'，mingshen: "shen"},]
    handleAnMingGongJiShenGong(state, { pos, val }) {
      const dataPos = state.dataList.find((p) => p.name.includes(pos)).pos4;
      for (let key in val) {
        dataPos[key] = val[key];
      }
    },
    // val => [{brother:"亥",luck:"辰",kids:"未"}]
    handleDingShiErGong(state, val) {
      Object.keys(val).forEach((name) => {
        let dataPos = state.dataList.find((p) =>
          p.name.includes(val[name])
        ).pos4;
        dataPos.minggong = name + "宫";
      });
    },
  },
  actions: {},
  modules: {},
});
